// ✅ BEST — kiểm tra cả chức năng lẫn accessibility
screen.getByRole('button', { name: /submit/i });
screen.getByLabelText('Email Address');

// ✅ OK — khi không có role/label phù hợp
screen.getByText('Đăng nhập thành công');
screen.getByPlaceholderText('Nhập email...');

// ⚠️ LAST RESORT — dùng khi không còn cách nào khác
// data-testid không phản ánh gì về UX thực tế
screen.getByTestId('submit-btn');

// <button>Đăng ký</button>
screen.getByRole('button', { name: 'Đăng ký' });

// <input type="checkbox" aria-label="Đồng ý điều khoản" />
screen.getByRole('checkbox', { name: /đồng ý/i });

// <h2>Giỏ hàng của bạn</h2>
screen.getByRole('heading', { level: 2, name: /giỏ hàng/i });

// <select> với options
screen.getByRole('combobox', { name: 'Tỉnh/Thành phố' });

// Kiểm tra state: checkbox đã checked chưa
screen.getByRole('checkbox', { name: 'Ghi nhớ đăng nhập', checked: true });

// Tất cả ARIA roles: https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Roles

// HTML: <label htmlFor="email">Địa chỉ email</label>
//       <input id="email" type="email" />
screen.getByLabelText('Địa chỉ email');

// HTML: <input aria-label="Tìm kiếm sản phẩm" />
screen.getByLabelText('Tìm kiếm sản phẩm');

// HTML: <input placeholder="Nhập số điện thoại" />
screen.getByPlaceholderText('Nhập số điện thoại');

// Tìm input đang có giá trị cụ thể
// HTML: <input value="user@example.com" />
screen.getByDisplayValue('user@example.com');

// HTML: <select><option selected>Hà Nội</option></select>
screen.getByDisplayValue('Hà Nội');

// getBy — element phải có mặt ngay
const title = screen.getByText('Chào mừng'); // throw nếu không thấy

// queryBy — kiểm tra element KHÔNG tồn tại
expect(screen.queryByText('Lỗi kết nối')).not.toBeInTheDocument();
// Nếu dùng getBy ở đây → throw Error thay vì fail gọn

// findBy — chờ element xuất hiện sau async operation
test('hiển thị danh sách sau khi load', async () => {
  render(<ProductList />);
  // fetch đang chạy, chờ tối đa 1 giây
  const items = await screen.findAllByRole('listitem');
  expect(items).toHaveLength(5);
});

// Sai: dùng getBy cho async → flaky test
// const items = screen.getAllByRole('listitem'); // fail ngay trước khi fetch xong

import userEvent from '@testing-library/user-event';

test('submit form với dữ liệu hợp lệ', async () => {
  const user = userEvent.setup(); // ← setup trước render
  const onSubmit = jest.fn();
  render(<LoginForm onSubmit={onSubmit} />);

  // Gõ vào input — mô phỏng đúng như user thực
  await user.type(screen.getByLabelText('Email'), 'test@example.com');
  await user.type(screen.getByLabelText('Mật khẩu'), 'Secret123');

  // Click button
  await user.click(screen.getByRole('button', { name: /đăng nhập/i }));

  expect(onSubmit).toHaveBeenCalledWith({
    email: 'test@example.com',
    password: 'Secret123',
  });
});

// Các actions khác:
// await user.clear(input)        — xóa giá trị input
// await user.selectOptions(select, 'Hà Nội')  — chọn option
// await user.keyboard('{Enter}') — nhấn phím Enter
// await user.tab()               — nhấn Tab để di chuyển focus

import { waitFor, waitForElementToBeRemoved } from '@testing-library/react';

// Chờ element xuất hiện sau fetch
test('load và hiển thị products', async () => {
  render(<ProductList />);

  // Cách 1: findBy (gọn hơn)
  const items = await screen.findAllByRole('listitem');
  expect(items).toHaveLength(3);

  // Cách 2: waitFor + getBy (dùng khi cần assert nhiều thứ)
  await waitFor(() => {
    expect(screen.getByText('Áo thun xanh')).toBeInTheDocument();
    expect(screen.getByText('Quần jean đen')).toBeInTheDocument();
  });
});

// Chờ loading spinner biến mất
test('ẩn spinner sau khi load xong', async () => {
  render(<ProductList />);
  await waitForElementToBeRemoved(() =>
    screen.getByRole('progressbar')
  );
  expect(screen.getByText('Tải xong!')).toBeInTheDocument();
});

// ❌ SAI: getBy cho async data
const items = screen.getAllByRole('listitem'); // fail ngay!
// ✅ ĐÚNG:
const items = await screen.findAllByRole('listitem');

// ❌ SAI: queryBy khi element phải có
const btn = screen.queryByRole('button', { name: 'Lưu' });
btn.click(); // TypeError: Cannot read properties of null
// ✅ ĐÚNG:
const btn = screen.getByRole('button', { name: 'Lưu' });

// ❌ SAI: quên await userEvent
user.click(screen.getByRole('button', { name: 'Gửi' })); // thiếu await!
expect(screen.getByText('Thành công')).toBeInTheDocument(); // fail
// ✅ ĐÚNG:
await user.click(screen.getByRole('button', { name: 'Gửi' }));

// ❌ SAI: dùng querySelector
const { container } = render(<Form />);
container.querySelector('input[type=email]').value; // brittle!
// ✅ ĐÚNG:
screen.getByRole('textbox', { name: 'Email' });

// TÓM TẮT: Map tình huống → query

// Element có ARIA role (button, input, heading...)
screen.getByRole('button', { name: /lưu/i });

// Form input có <label>
screen.getByLabelText('Họ và tên');

// Text hiển thị trên màn hình
screen.getByText(/thành công/i);

// Assert KHÔNG tồn tại
expect(screen.queryByText('Lỗi')).not.toBeInTheDocument();

// Sau async (fetch, setTimeout, animation)
await screen.findByText('Dữ liệu đã tải');

// Nhiều element cùng loại
const rows = screen.getAllByRole('row');
expect(rows).toHaveLength(6); // 5 data rows + 1 header

// Element có test-id (last resort)
screen.getByTestId('map-container');
